    fn COPYSCRN(&mut self) {
        let mut pc: u32 = 0;
        loop {
            match pc {
                0 => {
                    self.a = self.ram[sym::IMAGE + 1];
                    self.dst1_hi = self.a;
                    self.c = 0;
                    let _r = (self.a as u16) + (0x10) as u16 + (self.c as u16);
                    self.a = _r as u8;
                    self.c = (_r >> 8) as u8;
                    self.dst2_hi = self.a;
                    self.a = self.ram[sym::IMAGE];
                    self.org1_hi = self.a;
                    let _r = (self.a as u16) + (0x10) as u16 + (self.c as u16);
                    self.a = _r as u8;
                    self.c = (_r >> 8) as u8;
                    self.org2_hi = self.a;
                    self.x = 0x10;
                    self.y = 0x00;
                    pc = 1;
                }
                1 => {
                    pc = 2;
                }
                2 => {
                    self.a = self.ram[((self.org1_hi as usize) << 8 | (0x00)) + self.y as usize];
                    pc = 3;
                }
                3 => {
                    self.ram[((self.dst1_hi as usize) << 8 | (0x00)) + self.y as usize] = self.a;
                    pc = 4;
                }
                4 => {
                    self.a = self.ram[((self.org2_hi as usize) << 8 | (0x00)) + self.y as usize];
                    pc = 5;
                }
                5 => {
                    self.ram[((self.dst2_hi as usize) << 8 | (0x00)) + self.y as usize] = self.a;
                    self.y = self.y.wrapping_add(1);
                    if self.y != 0x00 {
                        pc = 1;
                    } else {
                        pc = 6;
                    }
                }
                6 => {
                    // raw: patch *:org1+2 += 1                         ; HIRES.S:2085
                    // raw: patch *:org2+2 += 1                         ; HIRES.S:2086
                    // raw: patch *:dst1+2 += 1                         ; HIRES.S:2087
                    // raw: patch *:dst2+2 += 1                         ; HIRES.S:2088
                    self.x = self.x.wrapping_sub(1);
                    if self.x != 0x00 {
                        pc = 1;
                    } else {
                        pc = 7;
                    }
                }
                7 => {
                    return;
                }
                _ => unreachable!(),
            }
        }
    }

    fn INVERTY(&mut self) {
        self.x = 0xbf;
        self.y = 0x00;
        loop {
            self.a = self.ram[sym::YLO + self.x as usize];
            let tmp0 = self.a;
            self.ram[sym::YLO + self.x as usize] = self.ram[sym::YLO + self.y as usize];
            self.a = tmp0;
            self.ram[sym::YLO + self.y as usize] = self.a;
            self.a = self.ram[sym::YHI + self.x as usize];
            let tmp1 = self.a;
            self.ram[sym::YHI + self.x as usize] = self.ram[sym::YHI + self.y as usize];
            self.a = tmp1;
            self.ram[sym::YHI + self.y as usize] = self.a;
            self.x = self.x.wrapping_sub(1);
            self.y = self.y.wrapping_add(1);
            let _o: u8 = 0x60;
            self.c = (self.y >= _o) as u8;
            self.z = (self.y == _o) as u8;
            self.n = self.y.wrapping_sub(_o) >> 7;
            if !(self.y < 0x60) {
                break;
            }
        }
        return;
    }
